// // This module resets the counter when offsetInc is asserted and increments it on the falling edge of Clk2
module top_module(output reg [3:0] offset, input Reset, input Clk2,
    input offsetInc);always@(posedge Clk2) begin
    if (Reset)
      offset <= 4'b0;
    else
      if (offsetInc)
        offset <= offset + 1;
      else
        offset <= offset;
  end

endmodule
